create table dirkspzm32.rep_grid_columns_cfg (
    rep_id                   number(*, 0) not null enable,
    field_name               varchar2(255 char) not null enable,
    column_visible           varchar2(10 char) default 'T' not null enable,
    title_caption            varchar2(255 char) not null enable,
    title_color              number(*, 5),
    title_font_color         number(*, 5),
    column_color             number(*, 5),
    column_font_color        number(*, 5),
    column_width             number(*, 5) not null enable,
    display_format           varchar2(100 char),
    edit_mask                varchar2(100 char),
    datatype                 varchar2(10 char),
    use_in_filter            varchar2(1 char) default 'F' not null enable,
    column_position          number(*, 5),
    grouping_level           number(*, 5),
    editor_type              varchar2(50 char),
    editor_params            clob,
    lookup_key_values        varchar2(2000 char),
    lookup_names             varchar2(2000 char),
    lookup_rep_name          varchar2(100 char),
    lookup_lang_const_prefix varchar2(50 char),
    default_value            varchar2(255 char),
    def_val_sys_var          varchar2(50 char),
    readonly                 varchar2(1 char) default 'T' not null enable,
    edit_security_level      number(*, 5) default 0 not null enable,
    merge_cells              varchar2(1 char) default 'F' not null enable,
    fixed_mode               varchar2(1 char) default 'N' not null enable,
    grp_summary_kind         number(*, 5) default 0 not null enable,
    grp_summary_pos          number(*, 5) default - 1 not null enable,
    footer_summary_kind      number(*, 5) default 0 not null enable
);

alter table dirkspzm32.rep_grid_columns_cfg
    add constraint pk_rep_grid_columns_cfg primary key ( rep_id,
                                                         field_name )
        using index enable;


